import {
  Component, OnInit, AfterViewChecked, OnDestroy,
  ViewChild, ElementRef, inject, signal, computed,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { LucideAngularModule } from 'lucide-angular';
import { SimulationStoreService } from '../../shared/simulation-store.service';
import { ApiService } from '../../shared/api.service';
import { Chart, registerables } from 'chart.js';

Chart.register(...registerables);

const PRIMARY      = '#00BCD4';
const PRIMARY_DARK = '#0288D1';
const GREEN        = '#43A047';
const ORANGE       = '#FB8C00';
const RED          = '#E53935';
const GRAY         = '#90A4AE';

interface KpiCard {
  label: string; unit: string; icon: string;
  beforeVal: number; afterVal: number; maxBar: number;
  lowerIsBetter: boolean; okThreshold: number; warnThreshold: number;
  delta: number;
}

type ApplyStatus = 'idle' | 'confirming' | 'loading' | 'success' | 'error';

@Component({
  selector: 'app-simulation-result',
  standalone: true,
  imports: [CommonModule, RouterLink, LucideAngularModule],
  template: `
<ng-container *ngIf="data() as d; else empty">
<div class="flex flex-col h-full bg-background relative">

  <!-- ══════════════════════════════════════════════════════════════════
       HEADER
  ══════════════════════════════════════════════════════════════════ -->
  <div class="px-6 lg:px-8 py-5 bg-card border-b">
    <div class="flex items-center justify-between flex-wrap gap-4">
      <div class="flex items-center gap-3">
        <a routerLink="/simulation"
           class="w-10 h-10 rounded-xl border border-border bg-card hover:bg-muted flex items-center justify-center transition-colors">
          <lucide-icon name="arrow-left" class="w-5 h-5 text-foreground"></lucide-icon>
        </a>
        <div class="w-11 h-11 rounded-xl flex items-center justify-center"
             [style.background]="'linear-gradient(135deg,'+PRIMARY+','+PRIMARY_DARK+')'">
          <lucide-icon name="activity" class="w-6 h-6 text-white"></lucide-icon>
        </div>
        <div>
          <h1 class="text-xl font-bold text-foreground font-display">Résultats de la simulation</h1>
          <p class="text-sm text-muted-foreground">Impact des décisions · Graphiques KPI · Comparaison AVANT / APRÈS</p>
        </div>
      </div>
      <div class="flex items-center gap-2 flex-wrap">
        <span *ngIf="applyStatus() === 'success'"
              class="text-xs px-3 py-1.5 rounded-full font-bold flex items-center gap-1.5"
              [style.backgroundColor]="GREEN+'18'" [style.color]="GREEN">
          <lucide-icon name="check-circle-2" class="w-3.5 h-3.5"></lucide-icon>
          Appliqué au système
        </span>
        <span class="text-xs px-3 py-1.5 rounded-full font-bold"
              [style.backgroundColor]="GREEN+'15'" [style.color]="GREEN">
          {{ d.result?.scenario_name || 'Simulation DES' }}
        </span>
        <span class="text-xs px-3 py-1.5 rounded-full font-semibold bg-muted text-muted-foreground">
          {{ d.input?.target_doctors || 0 }} méd. · {{ d.input?.target_nurses || 0 }} inf. · {{ d.input?.target_beds || 0 }} lits
        </span>
      </div>
    </div>
  </div>

  <!-- ══════════════════════════════════════════════════════════════════
       BODY
  ══════════════════════════════════════════════════════════════════ -->
  <div class="flex-1 overflow-y-auto p-6">
  <div class="max-w-5xl mx-auto space-y-6">

    <!-- ── LÉGENDE CODES COULEUR ── -->
    <div class="flex items-center gap-4 px-1 flex-wrap">
      <span class="text-xs text-muted-foreground font-semibold uppercase tracking-wider">Codes couleur :</span>
      <span class="flex items-center gap-1.5 text-xs font-semibold" [style.color]="GREEN">
        <span class="w-2.5 h-2.5 rounded-full" [style.backgroundColor]="GREEN"></span>Dans la norme
      </span>
      <span class="flex items-center gap-1.5 text-xs font-semibold" [style.color]="ORANGE">
        <span class="w-2.5 h-2.5 rounded-full" [style.backgroundColor]="ORANGE"></span>Attention
      </span>
      <span class="flex items-center gap-1.5 text-xs font-semibold" [style.color]="RED">
        <span class="w-2.5 h-2.5 rounded-full" [style.backgroundColor]="RED"></span>Critique
      </span>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 1 — IMPACT DES DÉCISIONS
    ══════════════════════════════════════════════════════════════ -->
    <div>
      <div class="flex items-center gap-2 px-1 mb-3">
        <span class="w-1.5 h-5 rounded-full" [style.backgroundColor]="PRIMARY"></span>
        <h2 class="text-sm font-bold text-foreground uppercase tracking-wider">Impact des décisions du scénario</h2>
      </div>
      <div class="bg-card rounded-2xl border border-border shadow-sm overflow-hidden">
        <table class="w-full text-sm">
          <thead>
            <tr class="bg-muted/40 text-xs font-semibold text-muted-foreground uppercase">
              <th class="text-left px-5 py-2.5 w-1/4">Décision / Ressource</th>
              <th class="text-left px-5 py-2.5 w-1/4">Modification apportée</th>
              <th class="text-left px-5 py-2.5">Effet observé sur le système</th>
              <th class="text-center px-4 py-2.5">Impact</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let row of decisionImpacts()" class="border-t border-border hover:bg-muted/20 transition-colors">
              <td class="px-5 py-3">
                <div class="flex items-center gap-2">
                  <lucide-icon [name]="row.icon" class="w-4 h-4 flex-shrink-0" [style.color]="PRIMARY"></lucide-icon>
                  <span class="font-medium text-foreground">{{ row.resource }}</span>
                </div>
              </td>
              <td class="px-5 py-3">
                <div class="flex items-center gap-2">
                  <span class="text-muted-foreground">{{ row.before }}</span>
                  <lucide-icon name="arrow-right" class="w-3.5 h-3.5 text-muted-foreground/50"></lucide-icon>
                  <span class="font-bold text-foreground">{{ row.after }}</span>
                </div>
              </td>
              <td class="px-5 py-3 text-muted-foreground text-xs leading-relaxed">{{ row.effect }}</td>
              <td class="px-4 py-3 text-center">
                <span class="inline-flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-full"
                      [style.backgroundColor]="row.impactColor+'15'" [style.color]="row.impactColor">
                  {{ row.impactLabel }}
                </span>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 2 — GRAPHIQUES KPI
         · Graphique à barres groupées (Chart.js) AVANT / APRÈS
         · Cartes KPI individuelles avec barres de progression
    ══════════════════════════════════════════════════════════════ -->
    <div>
      <div class="flex items-center gap-2 px-1 mb-3">
        <span class="w-1.5 h-5 rounded-full" [style.backgroundColor]="PRIMARY"></span>
        <h2 class="text-sm font-bold text-foreground uppercase tracking-wider">Indicateurs clés de performance (KPI)</h2>
      </div>

      <!-- ── Graphique à barres Chart.js ── -->
      <div class="bg-card rounded-2xl border border-border shadow-sm p-5 mb-4">
        <div class="flex items-center gap-2 mb-3">
          <lucide-icon name="bar-chart-2" class="w-4 h-4" [style.color]="PRIMARY"></lucide-icon>
          <span class="text-xs font-semibold text-foreground">Évolution AVANT → APRÈS</span>
          <span class="text-xs text-muted-foreground">(valeurs normalisées sur 100% du maximum par indicateur)</span>
        </div>
        <div class="relative" style="height:230px">
          <canvas #barCanvas></canvas>
        </div>
      </div>

      <!-- ── Cartes KPI ── -->
      <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        <div *ngFor="let kpi of kpis()"
             class="bg-card rounded-2xl border shadow-sm p-5 flex flex-col gap-4"
             [style.borderColor]="kpiColor(kpi)+'40'">

          <div class="flex items-center justify-between">
            <div class="flex items-center gap-2">
              <div class="w-8 h-8 rounded-lg flex items-center justify-center"
                   [style.backgroundColor]="PRIMARY+'15'">
                <lucide-icon [name]="kpi.icon" class="w-4 h-4" [style.color]="PRIMARY"></lucide-icon>
              </div>
              <span class="text-sm font-semibold text-foreground">{{ kpi.label }}</span>
            </div>
            <span class="text-[11px] font-bold px-2 py-0.5 rounded-full"
                  [style.backgroundColor]="kpiColor(kpi)+'18'" [style.color]="kpiColor(kpi)">
              {{ kpiStatus(kpi) }}
            </span>
          </div>

          <div class="space-y-2">
            <div class="flex items-center gap-2">
              <span class="text-[11px] text-muted-foreground font-medium w-10 flex-shrink-0">Avant</span>
              <div class="flex-1 h-4 rounded-full bg-muted overflow-hidden">
                <div class="h-full rounded-full transition-all duration-500"
                     style="background:#90A4AE"
                     [style.width.%]="barPct(kpi.beforeVal, kpi.maxBar)">
                </div>
              </div>
              <span class="text-[11px] font-bold text-muted-foreground w-14 text-right flex-shrink-0">
                {{ kpi.beforeVal }}<span class="font-normal ml-0.5">{{ kpi.unit }}</span>
              </span>
            </div>
            <div class="flex items-center gap-2">
              <span class="text-[11px] font-semibold w-10 flex-shrink-0" [style.color]="PRIMARY">Après</span>
              <div class="flex-1 h-4 rounded-full bg-muted overflow-hidden">
                <div class="h-full rounded-full transition-all duration-700"
                     [style.width.%]="barPct(kpi.afterVal, kpi.maxBar)"
                     [style.backgroundColor]="kpiColor(kpi)">
                </div>
              </div>
              <span class="text-[11px] font-bold w-14 text-right flex-shrink-0" [style.color]="kpiColor(kpi)">
                {{ kpi.afterVal }}<span class="font-normal ml-0.5">{{ kpi.unit }}</span>
              </span>
            </div>
          </div>

          <div class="flex items-end justify-between pt-1 border-t border-border/60">
            <div>
              <span class="text-2xl font-bold" [style.color]="kpiColor(kpi)">{{ kpi.afterVal }}</span>
              <span class="text-sm text-muted-foreground ml-1">{{ kpi.unit }}</span>
            </div>
            <div class="flex items-center gap-1 text-sm font-bold" [style.color]="deltaColor(kpi)">
              <lucide-icon [name]="deltaIcon(kpi)" class="w-4 h-4"></lucide-icon>
              {{ kpi.delta >= 0 ? '+' : '' }}{{ kpi.delta.toFixed(1) }}%
              <span class="text-xs font-normal text-muted-foreground ml-1">vs avant</span>
            </div>
          </div>

          <div class="flex gap-3 text-[10px] text-muted-foreground">
            <span class="flex items-center gap-1">
              <span class="w-1.5 h-1.5 rounded-full" [style.backgroundColor]="GREEN"></span>
              Norme {{ kpi.lowerIsBetter ? '≤ '+kpi.okThreshold : '≥ '+kpi.okThreshold }}{{ kpi.unit }}
            </span>
            <span class="flex items-center gap-1">
              <span class="w-1.5 h-1.5 rounded-full" [style.backgroundColor]="ORANGE"></span>
              Attention ≤ {{ kpi.warnThreshold }}{{ kpi.unit }}
            </span>
          </div>
        </div>
      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 3 — RÉPARTITION (diagrammes circulaires)
         · Occupation des lits
         · Utilisation du personnel médical
         · Couverture des services
    ══════════════════════════════════════════════════════════════ -->
    <div>
      <div class="flex items-center gap-2 px-1 mb-3">
        <span class="w-1.5 h-5 rounded-full" [style.backgroundColor]="PRIMARY"></span>
        <h2 class="text-sm font-bold text-foreground uppercase tracking-wider">Répartition — occupation et couverture (APRÈS simulation)</h2>
      </div>
      <div class="grid grid-cols-1 md:grid-cols-3 gap-4">

        <!-- Lits -->
        <div class="bg-card rounded-2xl border border-border shadow-sm p-5">
          <div class="flex items-center gap-2 mb-1">
            <lucide-icon name="bed" class="w-4 h-4" [style.color]="PRIMARY"></lucide-icon>
            <span class="text-sm font-semibold text-foreground">Occupation des lits</span>
          </div>
          <div class="text-xs text-muted-foreground mb-4">Taux de remplissage capacitaire</div>
          <div class="relative" style="height:180px">
            <canvas #doughnutBedsCanvas></canvas>
          </div>
          <div class="mt-3 text-center">
            <span class="text-2xl font-bold"
                  [style.color]="bedOccColor()">{{ bedOccVal() }}%</span>
            <span class="text-xs text-muted-foreground ml-1">occupés</span>
          </div>
        </div>

        <!-- Personnel médical -->
        <div class="bg-card rounded-2xl border border-border shadow-sm p-5">
          <div class="flex items-center gap-2 mb-1">
            <lucide-icon name="stethoscope" class="w-4 h-4" [style.color]="PRIMARY"></lucide-icon>
            <span class="text-sm font-semibold text-foreground">Personnel médical</span>
          </div>
          <div class="text-xs text-muted-foreground mb-4">Charge sur le corps médical (ρ)</div>
          <div class="relative" style="height:180px">
            <canvas #doughnutDoctorsCanvas></canvas>
          </div>
          <div class="mt-3 text-center">
            <span class="text-2xl font-bold"
                  [style.color]="docUtilColor()">{{ docUtilVal() }}%</span>
            <span class="text-xs text-muted-foreground ml-1">utilisés</span>
          </div>
        </div>

        <!-- Couverture services -->
        <div class="bg-card rounded-2xl border border-border shadow-sm p-5">
          <div class="flex items-center gap-2 mb-1">
            <lucide-icon name="shield-check" class="w-4 h-4" [style.color]="PRIMARY"></lucide-icon>
            <span class="text-sm font-semibold text-foreground">Couverture des services</span>
          </div>
          <div class="text-xs text-muted-foreground mb-4">Part des services opérationnels</div>
          <div class="relative" style="height:180px">
            <canvas #doughnutCoverageCanvas></canvas>
          </div>
          <div class="mt-3 text-center">
            <span class="text-2xl font-bold"
                  [style.color]="covColor()">{{ covVal() }}%</span>
            <span class="text-xs text-muted-foreground ml-1">couverts</span>
          </div>
        </div>

      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 4 — COMPARAISON AVANT / APRÈS
    ══════════════════════════════════════════════════════════════ -->
    <div>
      <div class="flex items-center gap-2 px-1 mb-3">
        <span class="w-1.5 h-5 rounded-full" [style.backgroundColor]="PRIMARY"></span>
        <h2 class="text-sm font-bold text-foreground uppercase tracking-wider">Comparaison AVANT / APRÈS</h2>
      </div>
      <div class="bg-card rounded-2xl border border-border shadow-sm overflow-hidden">
        <table class="w-full text-sm">
          <thead>
            <tr class="bg-muted/40 text-xs font-semibold text-muted-foreground uppercase">
              <th class="text-left px-5 py-2.5">Indicateur</th>
              <th class="text-right px-5 py-2.5">
                <span class="inline-flex items-center gap-1">
                  <span class="w-2.5 h-2.5 rounded-full" style="background:#90A4AE"></span>AVANT
                </span>
              </th>
              <th class="text-right px-5 py-2.5">
                <span class="inline-flex items-center gap-1" [style.color]="PRIMARY">
                  <span class="w-2.5 h-2.5 rounded-full" [style.backgroundColor]="PRIMARY"></span>APRÈS
                </span>
              </th>
              <th class="text-center px-5 py-2.5">Δ Variation</th>
              <th class="text-center px-5 py-2.5">Statut</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let row of compareRows()" class="border-t border-border hover:bg-muted/20 transition-colors">
              <td class="px-5 py-3 font-medium text-foreground">
                <div class="flex items-center gap-2">
                  <lucide-icon [name]="row.icon" class="w-3.5 h-3.5" [style.color]="PRIMARY"></lucide-icon>
                  {{ row.label }}
                </div>
              </td>
              <td class="px-5 py-3 text-right text-muted-foreground font-mono text-xs">{{ row.before }}</td>
              <td class="px-5 py-3 text-right font-bold font-mono text-xs" [style.color]="row.statusColor">{{ row.after }}</td>
              <td class="px-5 py-3 text-center">
                <span class="inline-flex items-center gap-1 text-xs font-bold"
                      [style.color]="row.improved ? GREEN : RED">
                  <lucide-icon [name]="row.improved ? 'trending-down' : 'trending-up'" class="w-3.5 h-3.5"
                               *ngIf="row.lowerIsBetter"></lucide-icon>
                  <lucide-icon [name]="row.improved ? 'trending-up' : 'trending-down'" class="w-3.5 h-3.5"
                               *ngIf="!row.lowerIsBetter"></lucide-icon>
                  {{ row.delta > 0 ? '+' : '' }}{{ row.delta.toFixed(1) }}%
                </span>
              </td>
              <td class="px-5 py-3 text-center">
                <span class="inline-block text-[11px] font-bold px-2 py-0.5 rounded-full"
                      [style.backgroundColor]="row.statusColor+'18'" [style.color]="row.statusColor">
                  {{ row.statusLabel }}
                </span>
              </td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 5 — CHARGE PAR SERVICE
    ══════════════════════════════════════════════════════════════ -->
    <div>
      <div class="flex items-center gap-2 px-1 mb-3">
        <span class="w-1.5 h-5 rounded-full" [style.backgroundColor]="PRIMARY"></span>
        <h2 class="text-sm font-bold text-foreground uppercase tracking-wider">Charge par service</h2>
      </div>
      <div class="bg-card rounded-2xl border border-border shadow-sm overflow-hidden">
        <div class="divide-y divide-border">
          <div *ngFor="let s of serviceLoads()" class="px-5 py-4 flex items-center gap-4 hover:bg-muted/20 transition-colors">
            <div class="w-48 flex-shrink-0">
              <div class="font-medium text-foreground text-sm">{{ s.name }}</div>
              <div class="text-[11px] text-muted-foreground mt-0.5">{{ s.desc }}</div>
            </div>
            <div class="flex-1">
              <div class="flex items-center gap-3">
                <div class="flex-1 h-3 rounded-full bg-muted overflow-hidden">
                  <div class="h-full rounded-full transition-all duration-500"
                       [style.width.%]="s.load"
                       [style.backgroundColor]="s.load >= 80 ? RED : s.load >= 60 ? ORANGE : GREEN">
                  </div>
                </div>
                <span class="text-sm font-bold w-12 text-right"
                      [style.color]="s.load >= 80 ? RED : s.load >= 60 ? ORANGE : GREEN">
                  {{ s.load }}%
                </span>
              </div>
              <div class="flex items-center gap-3 mt-1">
                <div class="flex-1 h-1.5 rounded-full bg-muted overflow-hidden">
                  <div class="h-full rounded-full bg-muted-foreground/30 transition-all duration-300"
                       [style.width.%]="s.before">
                  </div>
                </div>
                <span class="text-[11px] text-muted-foreground/70 w-12 text-right">{{ s.before }}% av.</span>
              </div>
            </div>
            <div class="w-24 text-right flex-shrink-0">
              <span class="text-[11px] font-bold px-2 py-0.5 rounded-full"
                    [style.backgroundColor]="(s.load >= 80 ? RED : s.load >= 60 ? ORANGE : GREEN)+'15'"
                    [style.color]="s.load >= 80 ? RED : s.load >= 60 ? ORANGE : GREEN">
                {{ s.load >= 80 ? 'Critique' : s.load >= 60 ? 'Attention' : 'Normal' }}
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 6 — PARAMÈTRES DU MODÈLE DES
    ══════════════════════════════════════════════════════════════ -->
    <div>
      <div class="flex items-center gap-2 px-1 mb-3">
        <span class="w-1.5 h-5 rounded-full" [style.backgroundColor]="PRIMARY"></span>
        <h2 class="text-sm font-bold text-foreground uppercase tracking-wider">Paramètres du modèle DES</h2>
      </div>
      <div class="bg-card rounded-2xl border border-border shadow-sm p-5">
        <div class="grid grid-cols-2 lg:grid-cols-4 gap-3 text-sm">
          <div class="bg-muted/30 rounded-xl p-3 border border-border/40">
            <div class="text-muted-foreground text-xs mb-1 flex items-center gap-1">
              <lucide-icon name="zap" class="w-3 h-3"></lucide-icon>λ (taux d'arrivée)
            </div>
            <div class="font-bold text-foreground">{{ d.result?.after?.lambda_rate || 0 }} patients/h</div>
          </div>
          <div class="bg-muted/30 rounded-xl p-3 border border-border/40">
            <div class="text-muted-foreground text-xs mb-1 flex items-center gap-1">
              <lucide-icon name="gauge" class="w-3 h-3"></lucide-icon>µ (taux de service)
            </div>
            <div class="font-bold text-foreground">{{ d.result?.after?.mu_rate || 0 }} patient/h</div>
          </div>
          <div class="bg-muted/30 rounded-xl p-3 border border-border/40">
            <div class="text-muted-foreground text-xs mb-1 flex items-center gap-1">
              <lucide-icon name="stethoscope" class="w-3 h-3"></lucide-icon>ρ médecins (APRÈS)
            </div>
            <div class="font-bold" [style.color]="rhoDoctorColor(d.result?.after?.rho_doctors)">
              {{ ((d.result?.after?.rho_doctors || 0)*100).toFixed(1) }}%
            </div>
          </div>
          <div class="bg-muted/30 rounded-xl p-3 border border-border/40">
            <div class="text-muted-foreground text-xs mb-1 flex items-center gap-1">
              <lucide-icon name="bed" class="w-3 h-3"></lucide-icon>ρ lits (APRÈS)
            </div>
            <div class="font-bold" [style.color]="rhoBedsColor(d.result?.after?.rho_beds)">
              {{ ((d.result?.after?.rho_beds || 0)*100).toFixed(1) }}%
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════════
         SECTION 7 — BOUTONS D'ACTION
         · Modifier le scénario  (retour à /simulation)
         · Appliquer au système  (avec confirmation + API Laravel)
    ══════════════════════════════════════════════════════════════ -->
    <div class="pb-6">
      <div class="bg-card rounded-2xl border border-border shadow-sm p-5">
        <div class="flex items-center gap-2 mb-4">
          <lucide-icon name="settings-2" class="w-4 h-4" [style.color]="PRIMARY"></lucide-icon>
          <span class="text-sm font-bold text-foreground">Actions sur le scénario</span>
        </div>

        <div class="flex flex-wrap items-start gap-4">

          <!-- MODIFIER LE SCÉNARIO -->
          <div class="flex-1 min-w-[200px]">
            <a routerLink="/simulation"
               class="w-full px-5 py-3 rounded-xl border-2 border-border bg-card hover:bg-muted text-sm font-semibold text-foreground inline-flex items-center justify-center gap-2 transition-colors">
              <lucide-icon name="arrow-left" class="w-4 h-4"></lucide-icon>
              Modifier le scénario
            </a>
            <p class="text-[11px] text-muted-foreground mt-1.5 px-1">
              Retourner au configurateur pour ajuster les paramètres.
            </p>
          </div>

          <!-- APPLIQUER AU SYSTÈME -->
          <div class="flex-1 min-w-[200px]">
            <!-- Idle / Error : bouton disponible -->
            <button *ngIf="applyStatus() === 'idle' || applyStatus() === 'error'"
                    (click)="startApply()"
                    class="w-full px-5 py-3 rounded-xl text-white font-semibold shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-2"
                    [style.background]="'linear-gradient(135deg,'+PRIMARY+','+PRIMARY_DARK+')'">
              <lucide-icon name="check-circle" class="w-4 h-4"></lucide-icon>
              Appliquer au système
            </button>

            <!-- Loading -->
            <button *ngIf="applyStatus() === 'loading'" disabled
                    class="w-full px-5 py-3 rounded-xl text-white font-semibold opacity-70 flex items-center justify-center gap-2"
                    [style.background]="'linear-gradient(135deg,'+PRIMARY+','+PRIMARY_DARK+')'">
              <lucide-icon name="loader-2" class="w-4 h-4 animate-spin"></lucide-icon>
              Application en cours…
            </button>

            <!-- Success -->
            <div *ngIf="applyStatus() === 'success'"
                 class="w-full px-5 py-3 rounded-xl flex items-center justify-center gap-2 text-sm font-bold"
                 [style.backgroundColor]="GREEN+'15'" [style.color]="GREEN">
              <lucide-icon name="check-circle-2" class="w-4 h-4"></lucide-icon>
              Scénario appliqué avec succès !
            </div>

            <!-- Error message -->
            <div *ngIf="applyStatus() === 'error'"
                 class="mt-1.5 flex items-center gap-1.5 text-[11px] font-semibold px-1"
                 [style.color]="RED">
              <lucide-icon name="alert-circle" class="w-3.5 h-3.5 flex-shrink-0"></lucide-icon>
              {{ applyError() }}
            </div>

            <p *ngIf="applyStatus() !== 'success'" class="text-[11px] text-muted-foreground mt-1.5 px-1">
              Applique officiellement ce scénario dans le système réel de gestion.
            </p>
          </div>

        </div>
      </div>
    </div>

  </div>
  </div>

  <!-- ══════════════════════════════════════════════════════════════
       MODAL DE CONFIRMATION — "Appliquer au système"
  ══════════════════════════════════════════════════════════════ -->
  <div *ngIf="applyStatus() === 'confirming'"
       class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 p-4"
       (click)="cancelApply()">
    <div class="bg-card rounded-2xl border border-border shadow-2xl w-full max-w-md space-y-5 p-6"
         (click)="$event.stopPropagation()">

      <!-- Header modal -->
      <div class="flex items-center gap-3">
        <div class="w-12 h-12 rounded-2xl flex items-center justify-center flex-shrink-0"
             [style.background]="'linear-gradient(135deg,'+PRIMARY+'20,'+PRIMARY_DARK+'20)'">
          <lucide-icon name="shield-check" class="w-6 h-6" [style.color]="PRIMARY"></lucide-icon>
        </div>
        <div>
          <h3 class="font-bold text-foreground text-base">Confirmer l'application</h3>
          <p class="text-xs text-muted-foreground">Cette action met à jour les ressources réelles de la structure.</p>
        </div>
      </div>

      <!-- Résumé du scénario -->
      <div class="bg-muted/40 rounded-xl p-4 space-y-3">
        <div class="flex items-center gap-2">
          <span class="text-xs font-semibold text-muted-foreground uppercase tracking-wider">Scénario :</span>
          <span class="text-sm font-bold text-foreground">{{ d.input?.scenario_name || 'Simulation DES' }}</span>
        </div>
        <div class="grid grid-cols-3 gap-3 text-center">
          <div class="bg-card rounded-xl p-3 border border-border">
            <div class="text-muted-foreground text-[11px] mb-0.5">Médecins</div>
            <div class="font-bold text-foreground text-xl">{{ d.input?.target_doctors || 0 }}</div>
          </div>
          <div class="bg-card rounded-xl p-3 border border-border">
            <div class="text-muted-foreground text-[11px] mb-0.5">Infirmiers</div>
            <div class="font-bold text-foreground text-xl">{{ d.input?.target_nurses || 0 }}</div>
          </div>
          <div class="bg-card rounded-xl p-3 border border-border">
            <div class="text-muted-foreground text-[11px] mb-0.5">Lits</div>
            <div class="font-bold text-foreground text-xl">{{ d.input?.target_beds || 0 }}</div>
          </div>
        </div>
      </div>

      <!-- Avertissement -->
      <div class="flex items-start gap-2.5 p-3 rounded-xl border"
           [style.backgroundColor]="ORANGE+'10'" [style.borderColor]="ORANGE+'30'">
        <lucide-icon name="triangle-alert" class="w-4 h-4 flex-shrink-0 mt-0.5" [style.color]="ORANGE"></lucide-icon>
        <p class="text-xs" [style.color]="ORANGE">
          Êtes-vous sûr de vouloir appliquer ce scénario ?
          Les ressources de la structure seront mises à jour dans le système réel de gestion hospitalière.
        </p>
      </div>

      <!-- Boutons -->
      <div class="flex gap-2 justify-end pt-1">
        <button (click)="cancelApply()"
                class="px-4 py-2.5 text-sm rounded-xl border border-border bg-card hover:bg-muted transition-colors font-medium">
          Annuler
        </button>
        <button (click)="confirmApply()"
                class="px-5 py-2.5 text-sm rounded-xl text-white font-semibold flex items-center gap-2 shadow-md transition-all"
                [style.background]="'linear-gradient(135deg,'+PRIMARY+','+PRIMARY_DARK+')'">
          <lucide-icon name="check-circle" class="w-4 h-4"></lucide-icon>
          Oui, appliquer
        </button>
      </div>

    </div>
  </div>

</div>
</ng-container>

<!-- ══════════════════════════════════════════════════════════════
     ÉCRAN VIDE
══════════════════════════════════════════════════════════════ -->
<ng-template #empty>
  <div class="flex flex-col h-full bg-background items-center justify-center p-6">
    <div class="bg-card rounded-2xl border border-border shadow-sm p-10 text-center max-w-md">
      <div class="w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4"
           [style.background]="'linear-gradient(135deg,'+PRIMARY+'15,'+PRIMARY_DARK+'15)'">
        <lucide-icon name="brain" class="w-8 h-8" [style.color]="PRIMARY"></lucide-icon>
      </div>
      <div class="font-bold text-foreground text-xl mb-1">Aucun résultat disponible</div>
      <div class="text-sm text-muted-foreground mb-5">
        Lancez d'abord une simulation depuis le centre de simulation.
      </div>
      <a routerLink="/simulation"
         class="px-5 py-2.5 rounded-xl text-white font-semibold shadow-md hover:shadow-lg transition-all inline-block"
         [style.background]="'linear-gradient(135deg,'+PRIMARY+','+PRIMARY_DARK+')'">
        Aller au centre de simulation
      </a>
    </div>
  </div>
</ng-template>
  `,
})
export class SimulationResultComponent implements OnInit, AfterViewChecked, OnDestroy {
  private store = inject(SimulationStoreService);
  private api   = inject(ApiService);

  readonly GREEN        = GREEN;
  readonly ORANGE       = ORANGE;
  readonly RED          = RED;
  readonly PRIMARY      = PRIMARY;
  readonly PRIMARY_DARK = PRIMARY_DARK;
  readonly GRAY         = GRAY;

  data        = signal<any>(null);
  applyStatus = signal<ApplyStatus>('idle');
  applyError  = signal<string>('');

  @ViewChild('barCanvas')             barCanvas?:             ElementRef<HTMLCanvasElement>;
  @ViewChild('doughnutBedsCanvas')    doughnutBedsCanvas?:    ElementRef<HTMLCanvasElement>;
  @ViewChild('doughnutDoctorsCanvas') doughnutDoctorsCanvas?: ElementRef<HTMLCanvasElement>;
  @ViewChild('doughnutCoverageCanvas') doughnutCoverageCanvas?: ElementRef<HTMLCanvasElement>;

  private barChart?:        Chart;
  private doughnutBeds?:    Chart;
  private doughnutDoctors?: Chart;
  private doughnutCoverage?: Chart;
  private chartsInitialized = false;

  // ── Lifecycle ──────────────────────────────────────────────────────────────
  ngOnInit() { this.data.set(this.store.get()); }

  ngAfterViewChecked() {
    if (!this.chartsInitialized && this.barCanvas?.nativeElement) {
      this.chartsInitialized = true;
      this.initCharts();
    }
  }

  ngOnDestroy() {
    this.barChart?.destroy();
    this.doughnutBeds?.destroy();
    this.doughnutDoctors?.destroy();
    this.doughnutCoverage?.destroy();
  }

  // ── Chart initialisation (Chart.js direct) ─────────────────────────────────
  private initCharts(): void {
    const d = this.data();
    if (!d?.result?.before || !d?.result?.after) return;
    const b   = d.result.before;
    const a   = d.result.after;
    const kps = this.kpis();
    if (!kps.length) return;

    const afterColors = kps.map(k => this.kpiColor(k));

    // ── Grouped horizontal bar chart ──────────────────────────────────────────
    if (this.barCanvas?.nativeElement) {
      this.barChart = new Chart(this.barCanvas.nativeElement, {
        type: 'bar',
        data: {
          labels: kps.map(k => k.label),
          datasets: [
            {
              label: 'AVANT',
              data: kps.map(k => +(k.beforeVal / k.maxBar * 100).toFixed(1)),
              backgroundColor: 'rgba(144,164,174,0.45)',
              borderColor: '#90A4AE',
              borderWidth: 1,
              borderRadius: 4,
            },
            {
              label: 'APRÈS',
              data: kps.map(k => +(k.afterVal / k.maxBar * 100).toFixed(1)),
              backgroundColor: afterColors.map(c => c + 'CC'),
              borderColor: afterColors,
              borderWidth: 1,
              borderRadius: 4,
            },
          ],
        },
        options: {
          indexAxis: 'y',
          responsive: true,
          maintainAspectRatio: false,
          plugins: {
            legend: {
              display: true,
              labels: { color: '#90A4AE', font: { size: 11 }, padding: 14, boxWidth: 14, boxHeight: 10 },
            },
            tooltip: {
              callbacks: {
                label: ctx => ` ${ctx.dataset.label}: ${ctx.raw}% du maximum`,
              },
            },
          },
          scales: {
            x: {
              min: 0, max: 100,
              ticks: { color: '#90A4AE', font: { size: 10 } },
              grid: { color: 'rgba(144,164,174,0.12)' },
            },
            y: {
              ticks: { color: '#90A4AE', font: { size: 10 } },
              grid: { display: false },
            },
          },
        },
      });
    }

    const doughnutBase: any = {
      responsive: true,
      maintainAspectRatio: false,
      cutout: '68%',
      plugins: {
        legend: {
          display: true,
          position: 'bottom',
          labels: { color: '#90A4AE', font: { size: 10 }, padding: 8, boxWidth: 12, boxHeight: 10 },
        },
      },
    };

    // ── Bed occupancy doughnut ──────────────────────────────────────────────────
    if (this.doughnutBedsCanvas?.nativeElement) {
      const occ   = Math.round(a.bed_occupancy_rate ?? 0);
      const color = occ >= 85 ? RED : occ >= 70 ? ORANGE : GREEN;
      this.doughnutBeds = new Chart(this.doughnutBedsCanvas.nativeElement, {
        type: 'doughnut',
        data: {
          labels: ['Occupés', 'Libres'],
          datasets: [{
            data: [occ, Math.max(0, 100 - occ)],
            backgroundColor: [color + 'CC', 'rgba(144,164,174,0.18)'],
            borderColor:     [color,         'rgba(144,164,174,0.3)'],
            borderWidth: 2,
          }],
        },
        options: doughnutBase,
      });
    }

    // ── Doctor utilisation doughnut ────────────────────────────────────────────
    if (this.doughnutDoctorsCanvas?.nativeElement) {
      const util  = Math.round((a.rho_doctors ?? 0) * 100);
      const color = util >= 85 ? RED : util >= 70 ? ORANGE : GREEN;
      this.doughnutDoctors = new Chart(this.doughnutDoctorsCanvas.nativeElement, {
        type: 'doughnut',
        data: {
          labels: ['Utilisés', 'Disponibles'],
          datasets: [{
            data: [util, Math.max(0, 100 - util)],
            backgroundColor: [color + 'CC', 'rgba(144,164,174,0.18)'],
            borderColor:     [color,         'rgba(144,164,174,0.3)'],
            borderWidth: 2,
          }],
        },
        options: doughnutBase,
      });
    }

    // ── Service coverage doughnut ──────────────────────────────────────────────
    if (this.doughnutCoverageCanvas?.nativeElement) {
      const cov   = Math.round(a.service_coverage ?? 0);
      const color = cov >= 80 ? GREEN : cov >= 60 ? ORANGE : RED;
      this.doughnutCoverage = new Chart(this.doughnutCoverageCanvas.nativeElement, {
        type: 'doughnut',
        data: {
          labels: ['Couverts', 'Non couverts'],
          datasets: [{
            data: [cov, Math.max(0, 100 - cov)],
            backgroundColor: [color + 'CC', 'rgba(144,164,174,0.18)'],
            borderColor:     [color,         'rgba(144,164,174,0.3)'],
            borderWidth: 2,
          }],
        },
        options: doughnutBase,
      });
    }
  }

  // ── Pie chart value helpers (for the numeric labels under each chart) ───────
  bedOccVal()  { return Math.round(this.data()?.result?.after?.bed_occupancy_rate ?? 0); }
  docUtilVal() { return Math.round((this.data()?.result?.after?.rho_doctors ?? 0) * 100); }
  covVal()     { return Math.round(this.data()?.result?.after?.service_coverage ?? 0); }

  bedOccColor()  { const v = this.bedOccVal();  return v >= 85 ? RED : v >= 70 ? ORANGE : GREEN; }
  docUtilColor() { const v = this.docUtilVal(); return v >= 85 ? RED : v >= 70 ? ORANGE : GREEN; }
  covColor()     { const v = this.covVal();     return v >= 80 ? GREEN : v >= 60 ? ORANGE : RED; }

  // ── Apply to system ────────────────────────────────────────────────────────
  startApply()  { this.applyStatus.set('confirming'); }
  cancelApply() { this.applyStatus.set('idle'); }

  confirmApply() {
    const d = this.data();
    if (!d?.input) return;
    this.applyStatus.set('loading');
    this.api.applyScenario(d.input.hospital_id, {
      doctors:       d.input.target_doctors,
      nurses:        d.input.target_nurses,
      beds:          d.input.target_beds,
      scenario_name: d.input.scenario_name,
    }).subscribe({
      next: () => this.applyStatus.set('success'),
      error: (err: any) => {
        this.applyError.set(
          err?.status === 404
            ? 'Endpoint en cours de déploiement côté serveur Laravel.'
            : 'Erreur serveur. Veuillez réessayer.',
        );
        this.applyStatus.set('error');
      },
    });
  }

  // ── KPI cards ──────────────────────────────────────────────────────────────
  kpis = computed((): KpiCard[] => {
    const d = this.data();
    if (!d?.result?.before || !d?.result?.after) return [];
    const b   = d.result.before;
    const a   = d.result.after;
    const imp = d.result.improvements || {};
    return [
      { label: "Temps d'attente",    unit: 'min', icon: 'clock',
        beforeVal: b.waiting_time_minutes ?? 0, afterVal: a.waiting_time_minutes ?? 0,
        maxBar: 60,  lowerIsBetter: true,  okThreshold: 20, warnThreshold: 40,
        delta: imp.waiting_time ?? 0 },
      { label: 'Occupation des lits', unit: '%',  icon: 'bed',
        beforeVal: b.bed_occupancy_rate ?? 0, afterVal: a.bed_occupancy_rate ?? 0,
        maxBar: 100, lowerIsBetter: true,  okThreshold: 70, warnThreshold: 85,
        delta: imp.bed_occupancy ?? 0 },
      { label: 'Débit patients',      unit: '/j', icon: 'trending-up',
        beforeVal: b.throughput_patients ?? 0, afterVal: a.throughput_patients ?? 0,
        maxBar: 60,  lowerIsBetter: false, okThreshold: 25, warnThreshold: 15,
        delta: imp.throughput ?? 0 },
      { label: 'Utilisation ressources', unit: '%', icon: 'activity',
        beforeVal: b.resource_utilization ?? 0, afterVal: a.resource_utilization ?? 0,
        maxBar: 100, lowerIsBetter: true,  okThreshold: 70, warnThreshold: 85,
        delta: imp.resource_utilization ?? 0 },
      { label: 'Couverture services', unit: '%', icon: 'shield-check',
        beforeVal: b.service_coverage ?? 0, afterVal: a.service_coverage ?? 0,
        maxBar: 100, lowerIsBetter: false, okThreshold: 80, warnThreshold: 60,
        delta: imp.service_coverage ?? 0 },
    ];
  });

  kpiColor(kpi: KpiCard): string {
    const v = kpi.afterVal;
    if (kpi.lowerIsBetter) return v <= kpi.okThreshold ? GREEN : v <= kpi.warnThreshold ? ORANGE : RED;
    return v >= kpi.okThreshold ? GREEN : v >= kpi.warnThreshold ? ORANGE : RED;
  }

  kpiStatus(kpi: KpiCard): string {
    const c = this.kpiColor(kpi);
    return c === GREEN ? 'Dans la norme' : c === ORANGE ? 'Attention' : 'Critique';
  }

  deltaColor(kpi: KpiCard): string {
    // Python improvement() retourne toujours positif = amélioration, négatif = dégradation
    return kpi.delta >= 0 ? GREEN : RED;
  }

  deltaIcon(kpi: KpiCard): string {
    if (kpi.lowerIsBetter) return kpi.delta >= 0 ? 'arrow-down' : 'arrow-up';
    return kpi.delta >= 0 ? 'arrow-up' : 'arrow-down';
  }

  barPct(val: number, max: number): number { return Math.min(100, Math.max(0, (val / max) * 100)); }

  // ── Decision impacts ────────────────────────────────────────────────────────
  decisionImpacts = computed(() => {
    const d = this.data();
    if (!d?.result?.before || !d?.result?.after || !d?.input) return [];
    const b   = d.result.before;
    const a   = d.result.after;
    const inp = d.input;

    const wtDelta  = (a.waiting_time_minutes ?? 0) - (b.waiting_time_minutes ?? 0);
    const bedDelta = (a.bed_occupancy_rate   ?? 0) - (b.bed_occupancy_rate   ?? 0);
    const thrDelta = (a.throughput_patients  ?? 0) - (b.throughput_patients  ?? 0);

    return [
      {
        icon: 'stethoscope', resource: 'Personnel médical',
        before: `${Math.round((inp.target_doctors || 0) * 0.8)} méd. / ${Math.round((inp.target_nurses || 0) * 0.8)} inf.`,
        after:  `${inp.target_doctors || 0} méd. / ${inp.target_nurses || 0} inf.`,
        effect: `Temps d'attente ${wtDelta <= 0
          ? 'réduit de ' + Math.abs(wtDelta).toFixed(0) + ' min'
          : 'augmenté de ' + wtDelta.toFixed(0) + ' min'} · Débit patients modifié`,
        impactColor: wtDelta <= 0 ? GREEN : RED,
        impactLabel: wtDelta <= 0 ? 'Amélioration' : 'Dégradation',
      },
      {
        icon: 'bed', resource: 'Capacité lits',
        before: `${Math.round((inp.target_beds || 0) * 0.85)} lits`,
        after:  `${inp.target_beds || 0} lits`,
        effect: `Taux d'occupation ${bedDelta <= 0 ? 'amélioré' : 'dégradé'} (${b.bed_occupancy_rate ?? 0}% → ${a.bed_occupancy_rate ?? 0}%)`,
        impactColor: bedDelta <= 0 ? GREEN : ORANGE,
        impactLabel: bedDelta <= 0 ? 'Amélioration' : 'Surveillance',
      },
      {
        icon: 'package', resource: 'Équipements',
        before: `${Math.round((inp.available_equipment || 0) * 0.8)} éq.`,
        after:  `${inp.available_equipment || 0} éq.`,
        effect: `Débit patients ${thrDelta >= 0
          ? 'augmenté de ' + thrDelta.toFixed(0) + '/j'
          : 'réduit de ' + Math.abs(thrDelta).toFixed(0) + '/j'} · Utilisation ressources ajustée`,
        impactColor: thrDelta >= 0 ? GREEN : ORANGE,
        impactLabel: thrDelta >= 0 ? 'Amélioration' : 'Surveillance',
      },
    ];
  });

  // ── Comparison table ────────────────────────────────────────────────────────
  compareRows = computed(() => {
    const d = this.data();
    if (!d?.result?.before || !d?.result?.after) return [];
    const b   = d.result.before;
    const a   = d.result.after;
    const imp = d.result.improvements ?? {};

    const make = (
      label: string, icon: string,
      bv: number, av: number, unit: string,
      delta: number, lowerIsBetter: boolean, okT: number, warnT: number,
    ) => {
      const improved = delta >= 0;
      const statusColor = lowerIsBetter
        ? (av <= okT ? GREEN : av <= warnT ? ORANGE : RED)
        : (av >= okT ? GREEN : av >= warnT ? ORANGE : RED);
      return {
        label, icon,
        before: `${bv}${unit}`, after: `${av}${unit}`,
        delta, improved, statusColor, lowerIsBetter,
        statusLabel: statusColor === GREEN ? 'Normal' : statusColor === ORANGE ? 'Attention' : 'Critique',
      };
    };

    return [
      make("Temps d'attente",      'clock',       b.waiting_time_minutes ?? 0, a.waiting_time_minutes ?? 0, ' min', imp.waiting_time      ?? 0, true,  20, 40),
      make('Occupation des lits',  'bed',          b.bed_occupancy_rate   ?? 0, a.bed_occupancy_rate   ?? 0, '%',    imp.bed_occupancy      ?? 0, true,  70, 85),
      make('Débit patients/jour',  'trending-up',  b.throughput_patients  ?? 0, a.throughput_patients  ?? 0, '/j',   imp.throughput         ?? 0, false, 25, 15),
      make('Utilisation ressources','activity',    b.resource_utilization ?? 0, a.resource_utilization ?? 0, '%',    imp.resource_utilization ?? 0, true, 70, 85),
      make('Couverture services',  'shield-check', b.service_coverage     ?? 0, a.service_coverage     ?? 0, '%',    imp.service_coverage   ?? 0, false, 80, 60),
    ];
  });

  // ── Service loads ───────────────────────────────────────────────────────────
  serviceLoads = computed(() => {
    const d = this.data();
    if (!d?.result?.after) return [];
    const a = d.result.after;
    const b = d.result.before ?? {};
    return [
      { name: 'Utilisation médecins',   desc: 'Charge du personnel médical',    load: Math.round((a.rho_doctors         ?? 0) * 100), before: Math.round((b.rho_doctors         ?? 0) * 100) },
      { name: 'Occupation lits',        desc: 'Taux de remplissage capacitaire', load: Math.round(a.bed_occupancy_rate   ?? 0),       before: Math.round(b.bed_occupancy_rate   ?? 0) },
      { name: 'Couverture services',    desc: 'Part des services opérationnels', load: Math.round(a.service_coverage     ?? 0),       before: Math.round(b.service_coverage     ?? 0) },
      { name: 'Utilisation ressources', desc: 'Équipements et matériel',         load: Math.round(a.resource_utilization ?? 0),       before: Math.round(b.resource_utilization ?? 0) },
    ];
  });

  // ── DES helpers ─────────────────────────────────────────────────────────────
  rhoDoctorColor(rho: number | undefined): string {
    const v = (rho ?? 0) * 100;
    return v < 70 ? GREEN : v < 85 ? ORANGE : RED;
  }
  rhoBedsColor(rho: number | undefined): string {
    const v = (rho ?? 0) * 100;
    return v < 70 ? GREEN : v < 85 ? ORANGE : RED;
  }
}
